def diagnose_failures(
    result: EvalResult,
    cases: list[dict]
) -> dict:
    failed_cases = [c for c in cases if c["id"] in result.failed]
    # Group failures by tag to find patterns
    by_tag: dict[str, list] = {}
    for c in failed_cases:
        for tag in c.get("tags", ["untagged"]):
            by_tag.setdefault(tag, []).append(c)
    # Compute failure rate per tag
    tag_failure_rate = {}
    for tag, failures in by_tag.items():
        total_with_tag = sum(1 for c in cases if tag in c.get("tags", []))
        tag_failure_rate[tag] = len(failures) / total_with_tag
    return {
        "total_failures": len(failed_cases),
        "by_tag": {k: len(v) for k, v in by_tag.items()},
        "failure_rate_by_tag": dict(sorted(
            tag_failure_rate.items(), key=lambda x: -x[1]
        ))
    }

diagnosis = diagnose_failures(baseline, eval_cases)
print("Failure rate by category:", json.dumps(diagnosis["failure_rate_by_tag"], indent=2))

from dataclasses import dataclass, field, asdict
from pathlib import Path
import json

@dataclass
class PromptVersion:
    version: str
    prompt: str
    pass_rate: float
    regressions: list[str]
    change_description: str
    accepted: bool
    notes: str = ""

class PromptVersionStore:
    def __init__(self, path: str = "prompt_versions.json"):
        self.path = Path(path)
        self._versions: list[PromptVersion] = []
        if self.path.exists():
            data = json.loads(self.path.read_text())
            self._versions = [PromptVersion(**d) for d in data]

    def add(self, version: PromptVersion):
        self._versions.append(version)
        self.path.write_text(json.dumps([asdict(v) for v in self._versions], indent=2))

    def best(self) -> PromptVersion | None:
        accepted = [v for v in self._versions if v.accepted]
        return max(accepted, key=lambda v: v.pass_rate) if accepted else None

    def summary(self) -> str:
        lines = [f"{v.version}: pass_rate={v.pass_rate:.1%} {'✓' if v.accepted else '✗'} — {v.change_description}" for v in self._versions]
        return "\n".join(lines)
